import{_ as a,o as r,c as s,ae as i}from"./chunks/framework.BuvKvcPh.js";const t="/Furniture-Designer/images/assembly-fr.png",g=JSON.parse('{"title":"Assemblage & Impression 3D","description":"","frontmatter":{},"headers":[],"relativePath":"fr/assembly.md","filePath":"fr/assembly.md"}'),n={name:"fr/assembly.md"};function l(o,e,u,d,c,p){return r(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="assemblage-impression-3d" tabindex="-1">Assemblage &amp; Impression 3D <a class="header-anchor" href="#assemblage-impression-3d" aria-label="Permalink to &quot;Assemblage &amp; Impression 3D&quot;">​</a></h1><p>Ce logiciel privilégie la conception invisible par chevilles en bois (tourillons).</p><p><img src="'+t+'" alt="Interface Outils d&#39;Assemblage"></p><h2 id="calcul-des-percages" tabindex="-1">Calcul des Perçages <a class="header-anchor" href="#calcul-des-percages" aria-label="Permalink to &quot;Calcul des Perçages&quot;">​</a></h2><p>Les positions des tourillons sont déduites algorithmiquement à chaque croisement parfait de deux planches (ex: une étagère reposant contre un montant).</p><p>Vous maîtrisez les paramètres globaux d&#39;assemblage :</p><ul><li><strong>Diamètre</strong> : Historiquement 8mm.</li><li><strong>Longueur du Tourillon</strong> : Indiquez la longueur physique d&#39;un tourillon. L&#39;algorithme se chargera de calculer les profondeurs respectives de vos forets selon qu&#39;ils percent en face ou en traverse.</li><li><strong>Marge au Bord</strong> : La distance de sécurité depuis les angles.</li><li><strong>Espacement</strong> : L&#39;écart maximal toléré entre deux tourillons consécutifs sur de grandes intersections.</li></ul><h2 id="gabarits-imprimables-3d-jigs" tabindex="-1">Gabarits Imprimables 3D (Jigs) <a class="header-anchor" href="#gabarits-imprimables-3d-jigs" aria-label="Permalink to &quot;Gabarits Imprimables 3D (Jigs)&quot;">​</a></h2><p>Percer de manière parfaitement perpendiculaire avec une cale s&#39;apprend difficilement. Pour annuler ce risque d&#39;erreur au montage, le système génère ses propres <strong>Guides d&#39;Imprimante 3D</strong> calibrés et ajustés <em>à la fraction de millimètre</em> de l&#39;épaisseur du meuble.</p><h3 id="_1-le-guide-de-chant-edge-guide" tabindex="-1">1. Le Guide de Chant (Edge Guide) <a class="header-anchor" href="#_1-le-guide-de-chant-edge-guide" aria-label="Permalink to &quot;1. Le Guide de Chant (Edge Guide)&quot;">​</a></h3><p>Un bloc en profilé-U pensé pour engloutir le chant de la planche. Il offre un unique trou pilote parfaitement centré pour lisser le parcours de votre mèche à bois sans jamais dévier.</p><h3 id="_2-le-guide-de-face-guide-equerre" tabindex="-1">2. Le Guide de Face (Guide Équerre) <a class="header-anchor" href="#_2-le-guide-de-face-guide-equerre" aria-label="Permalink to &quot;2. Le Guide de Face (Guide Équerre)&quot;">​</a></h3><p>Une pièce avec ergot (forme de L) qui viendra s&#39;ancrer dans le vide sur la surface du panneau. Le trou pilote est décalé pour s&#39;assurer que les connecteurs correspondent symétriquement et fermement au morceau de bois de chant opposé.</p><h3 id="exportations" tabindex="-1">Exportations <a class="header-anchor" href="#exportations" aria-label="Permalink to &quot;Exportations&quot;">​</a></h3><ul><li><strong>STL</strong> : Téléchargez les gabarits, envoyez-les dans Cura/PrusaSlicer, et imprimez (généralement aucune structure de support nécessaire et imprimable en moins d&#39;une heure).</li><li><strong>DXF</strong> : Les puristes opérant avec une défonceuse numérique (CNC) peuvent récupérer l&#39;ensemble de la coupe 2D superposée.</li></ul>',15)])])}const h=a(n,[["render",l]]);export{g as __pageData,h as default};
